windows_ffiget_arg_length:
     movq    %rcx, %r9
     movq    %rdx, %r8
     movq    %rsi, %rdx
     movq    %rdi, %rcx
     jmp     cdecl(ffiget_arg_length)

windows_ffiget_arg:
     movq    %rcx, %r9
     movq    %rdx, %r8
     movq    %rsi, %rdx
     movq    %rdi, %rcx
     jmp     cdecl(ffiget_arg)

windows_ffiget_arg_count:
     movq    %rcx, %r9
     movq    %rdx, %r8
     movq    %rsi, %rdx
     movq    %rdi, %rcx
     jmp     cdecl(ffiget_arg_count)

windows_ffiopen_in:
     movq    %rcx, %r9
     movq    %rdx, %r8
     movq    %rsi, %rdx
     movq    %rdi, %rcx
     jmp     cdecl(ffiopen_in)

windows_fficlose:
     movq    %rcx, %r9
     movq    %rdx, %r8
     movq    %rsi, %rdx
     movq    %rdi, %rcx
     jmp     cdecl(fficlose)

windows_ffiwrite:
     movq    %rcx, %r9
     movq    %rdx, %r8
     movq    %rsi, %rdx
     movq    %rdi, %rcx
     jmp     cdecl(ffiwrite)

windows_ffiread:
